it('should return null for empty input', () => {
  // Arrange
  const sut = new UserService(mockRepo);

  // Act
  const result = sut.findByEmail('');

  // Assert
  expect(result).toBeNull();
});

func TestCalculateTotal_WithDiscount(t *testing.T) {
    // Arrange
    order := Order{Items: []Item{{Price: 100.00}}, DiscountRate: 0.10}

    // Act
    total, err := CalculateTotal(order)

    // Assert
    if err != nil {
        t.Fatalf("unexpected error: %v", err)
    }
    if total != 90.00 {
        t.Errorf("expected 90.00, got %.2f", total)
    }
}

